-- ====================================\n-- 创建告警表\n-- ====================================\n\n-- 检查告警表是否存在\nDO $$\nBEGIN\n    IF NOT EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'alerts') THEN\n        CREATE TABLE alerts (\n            alert_id SERIAL PRIMARY KEY,\n            vehicle_id INTEGER REFERENCES vehicles(vehicle_id),\n            alert_type VARCHAR(100) NOT NULL,\n            priority INTEGER NOT NULL DEFAULT 0,\n            status INTEGER NOT NULL DEFAULT 0,\n            created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n            processed_at TIMESTAMP WITH TIME ZONE,\n            description TEXT,\n            location JSONB,\n            metadata JSONB\n        );
        \n        -- 创建索引\n        CREATE INDEX idx_alerts_vehicle_id ON alerts(vehicle_id);\n        CREATE INDEX idx_alerts_created_at ON alerts(created_at);\n        CREATE INDEX idx_alerts_status ON alerts(status);\n        CREATE INDEX idx_alerts_priority ON alerts(priority);\n        \n        RAISE NOTICE '创建表 alerts 成功';\n    ELSE\n        RAISE NOTICE '表 alerts 已存在';\n    END IF;\nEND $$;\n\n-- 插入示例数据\nINSERT INTO alerts (vehicle_id, alert_type, priority, status, description)\nVALUES \n    (1, 'overSpeed', 2, 0, '车辆超速'),\n    (2, 'fatigue', 1, 1, '疲劳驾驶'),\n    (3, 'overload', 2, 0, '车辆超载'),\n    (4, 'overspeed', 1, 0, '车辆超速'),\n    (5, 'fatigue', 2, 0, '疲劳驾驶')\nON CONFLICT DO NOTHING;\n\nSELECT '告警表创建完成！' AS info;

